cd /tmp/sv-1c0e54ea280e47b086ad5c22317ec267
# The replay recreated the build but sources aren't here. Let me extract more from the binlog using structured logger
# Let me try the binary reader approach with a simple C# script
cat > /tmp/analyze_binlog.cs << 'CSHARP'
// Read binlog and extract structured info
using System;
using System.IO;
using Microsoft.Build.Logging;
using Microsoft.Build.Framework;
using System.Collections.Generic;

var reader = new BinaryLogReplayEventSource();
var errors = new List<(string File, int Line, string Code, string Message, string Project)>();
var warnings = new List<(string File, int Line, string Code, string Message, string Project)>();
var projects = new Dictionary<string, string>(); // contextId -> project

reader.ErrorRaised += (sender, e) => {
    errors.Add((e.File ?? "", e.LineNumber, e.Code ?? "", e.Message ?? "", e.ProjectFile ?? ""));
};

reader.WarningRaised += (sender, e) => {
    warnings.Add((e.File ?? "", e.LineNumber, e.Code ?? "", e.Message ?? "", e.ProjectFile ?? ""));
};

reader.Replay(args[0]);

Console.WriteLine("=== ERRORS ===");
foreach (var err in errors)
{
    Console.WriteLine($"  [{err.Code}] {err.File}({err.Line}): {err.Message}");
    Console.WriteLine($"    Project: {err.Project}");
}

Console.WriteLine($"\n=== WARNINGS ===");
foreach (var w in warnings)
{
    Console.WriteLine($"  [{w.Code}] {w.File}({w.Line}): {w.Message}");
    Console.WriteLine($"    Project: {w.Project}");
}

Console.WriteLine($"\nTotal: {errors.Count} error(s), {warnings.Count} warning(s)");
CSHARP

# Create a project to run this
mkdir -p /tmp/binlog-analyzer
cat > /tmp/binlog-analyzer/binlog-analyzer.csproj << 'XML'
<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net8.0</TargetFramework>
  </PropertyGroup>
  <ItemGroup>
    <PackageReference Include="Microsoft.Build.Framework" Version="17.12.6" />
    <PackageReference Include="MSBuild.StructuredLogger" Version="2.2.400" />
  </ItemGroup>
</Project>
XML
